def is_ipv4(target):

    # Check if target is a string
    if not isinstance(target, str):
        return False

    # Split into octets
    octets = target.split('.')

    # IPv4 must have exactly 4 octets
    if len(octets) != 4:
        return False

    # Check each octet
    for octet in octets:
        # Check if octet is numeric
        if not octet.isdigit():
