    # Check if tag contains only alphanumeric chars and underscores
    if not tag.replace('_','').isalnum():
        return False

    # Check if tag starts with a letter
    if not tag[0].isalpha():
        return False

    # Check if tag is all lowercase
    if not tag.islower():
        return False

    return True

